import{get_string as getString}from"core/str";export const COMMAND_ALIGNJUSTIFY="alignjustify";const ICON_SVG='<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 16 16">'+'<path fill-rule="evenodd" d="M2 12.5a.5.5 0 0 1 .5-.5h11a.5.5 0 0 1 0 1h-11a.5.5 0 0 1-.5-.5z"/>'+'<path fill-rule="evenodd" d="M2 9.5a.5.5 0 0 1 .5-.5h11a.5.5 0 0 1 0 1h-11a.5.5 0 0 1-.5-.5z"/>'+'<path fill-rule="evenodd" d="M2 6.5a.5.5 0 0 1 .5-.5h11a.5.5 0 0 1 0 1h-11a.5.5 0 0 1-.5-.5z"/>'+'<path fill-rule="evenodd" d="M2 3.5a.5.5 0 0 1 .5-.5h11a.5.5 0 0 1 0 1h-11a.5.5 0 0 1-.5-.5z"/>'+"</svg>";const ICON_NAME="tiny_justify_icon";export const getSetup=async()=>{const tooltip=await getString("alignjustify","tiny_justify");const menutext=await getString("alignjustifymenu","tiny_justify");const onAction=editor=>()=>editor.execCommand("JustifyFull");const onSetup=editor=>api=>{editor.on("NodeChange",()=>{api.setActive(editor.queryCommandState("JustifyFull"))})};const registerAlignSubmenuItem=editor=>{const menuItems=editor.ui.registry.getAll().menuItems;const alignMenu=menuItems.align;if(alignMenu&&typeof alignMenu.getSubmenuItems==="function"){editor.ui.registry.addNestedMenuItem("align",{text:alignMenu.text,getSubmenuItems:()=>{const submenuItems=alignMenu.getSubmenuItems();return[...submenuItems,{type:"togglemenuitem",text:menutext,icon:ICON_NAME,onAction:onAction(editor),onSetup:onSetup(editor)}]}})}};return editor=>{editor.ui.registry.addIcon(ICON_NAME,ICON_SVG);editor.ui.registry.addToggleButton(COMMAND_ALIGNJUSTIFY,{tooltip:tooltip,icon:ICON_NAME,onAction:onAction(editor),onSetup:onSetup(editor)});editor.ui.registry.addToggleMenuItem(COMMAND_ALIGNJUSTIFY,{text:menutext,icon:ICON_NAME,onAction:onAction(editor),onSetup:onSetup(editor)});registerAlignSubmenuItem(editor);editor.on("init",()=>{setTimeout(()=>{registerAlignSubmenuItem(editor)},0)})}};